/**
 * Stanza Parser
 * Identifies verse structure from tokenized lines
 * Nexus - 2026-03-04
 */

import type { Line } from './Tokenizer';

export interface Stanza {
  lines: Line[];
  lineNumbers: number[];
  lineCount: number;
  leadingWhitespace: string;
}

export interface PoemStructure {
  stanzas: Stanza[];
  totalLines: number;
  totalStanzas: number;
  hasConsistentIndentation: boolean;
}

export class StanzaParser {
  parseStanzas(lines: Line[]): PoemStructure {
    const stanzas: Stanza[] = [];
    let currentStanzaLines: Line[] = [];

    for (const line of lines) {
      if (line.isEmpty && currentStanzaLines.length > 0) {
        // End of stanza
        stanzas.push(this.createStanza(currentStanzaLines));
        currentStanzaLines = [];
      } else if (!line.isEmpty) {
        currentStanzaLines.push(line);
      }
    }

    // Don't forget the last stanza
    if (currentStanzaLines.length > 0) {
      stanzas.push(this.createStanza(currentStanzaLines));
    }

    return {
      stanzas,
      totalLines: lines.filter(l => !l.isEmpty).length,
      totalStanzas: stanzas.length,
      hasConsistentIndentation: this.checkIndentationConsistency(stanzas)
    };
  }

  private createStanza(lines: Line[]): Stanza {
    const firstLine: Line | undefined = lines[0];
    return {
      lines,
      lineNumbers: lines.map(l => l.lineNumber),
      lineCount: lines.length,
      leadingWhitespace: firstLine ? firstLine.leadingWhitespace : ''
    };
  }

  private checkIndentationConsistency(stanzas: Stanza[]): boolean {
    if (stanzas.length === 0) return true;
    const firstStanza: Stanza | undefined = stanzas[0];
    if (!firstStanza) return true;
    const firstWhitespace = firstStanza.leadingWhitespace;
    return stanzas.every(s => s.leadingWhitespace === firstWhitespace);
  }

  detectMeter(lines: Line[]): string {
    // Simple syllable counting per line
    const syllableCounts = lines.map(line => 
      this.countSyllablesInLine(line)
    );

    if (syllableCounts.length === 0) return 'unknown';

    // Check if consistent (potential metrical pattern)
    const uniqueCounts = [...new Set(syllableCounts)];
    const isConsistent = uniqueCounts.length <= 2;

    const avgCount = syllableCounts.reduce((a, b) => a + b, 0) / syllableCounts.length;

    if (isConsistent && avgCount >= 9 && avgCount <= 11) {
      return 'likely-verse';
    } else if (avgCount > 15) {
      return 'likely-prose';
    }

    return 'mixed';
  }

  private countSyllablesInLine(line: Line): number {
    // Simple approximation: count vowel groups
    const text = line.text.toLowerCase();
    const vowelGroups = text.match(/[aeiouy]+/g);
    return vowelGroups ? vowelGroups.length : 0;
  }
}

export interface Token {
  type: 'word' | 'punctuation' | 'whitespace' | 'newline';
  value: string;
  lineNumber: number;
  charPosition: number;
}

export interface Line {
  tokens: Token[];
  text: string;
  lineNumber: number;
  isEmpty: boolean;
  leadingWhitespace: string;
}

export class Tokenizer {
  tokenize(input: string): Line[] {
    return input.split('\n').map((text, idx) => this.tokenizeLine(text, idx + 1));
  }

  private tokenizeLine(text: string, lineNum: number): Line {
    const tokens: Token[] = [];
    let pos = 0;
    let charPos = 0;

    const leadingMatch = text.match(/^(\s*)/);
    const leadingWhitespace = leadingMatch?.[1] ?? '';
    pos = leadingWhitespace.length;

    while (pos < text.length) {
      const char = text.charAt(pos);

      if (char === ' ' || char === '\t') {
        let ws = '';
        while (pos < text.length) {
          const c = text.charAt(pos);
          if (c !== ' ' && c !== '\t') break;
          ws += c;
          pos++;
        }
        tokens.push({ type: 'whitespace', value: ws, lineNumber: lineNum, charPosition: charPos });
      } else if (/[a-zA-Z0-9]/.test(char)) {
        let w = '';
        while (pos < text.length) {
          const c = text.charAt(pos);
          if (!/[a-zA-Z0-9]/.test(c)) break;
          w += c;
          pos++;
        }
        tokens.push({ type: 'word', value: w, lineNumber: lineNum, charPosition: charPos });
      } else {
        tokens.push({ type: 'punctuation', value: char, lineNumber: lineNum, charPosition: charPos });
        pos++;
      }
      charPos = pos;
    }

    return {
      tokens,
      text,
      lineNumber: lineNum,
      isEmpty: text.trim().length === 0,
      leadingWhitespace
    };
  }
}

import { describe, expect, test } from 'vitest';
import { Tokenizer } from './Tokenizer';
import { StanzaParser } from './StanzaParser';

describe('Poetry Processing Integration', () => {
  test('tokenizer feeds parser for verse detection', () => {
    const tokenizer = new Tokenizer();
    const parser = new StanzaParser();

    const poem = `The sun is warm
The sky is blue

The earth awake`;

    const lines = tokenizer.tokenize(poem);
    const structure = parser.parseStanzas(lines);

    expect(structure.totalStanzas).toBe(2);
    expect(structure.totalLines).toBe(3);
    const firstStanza = structure.stanzas[0];
    const secondStanza = structure.stanzas[1];
    if (!firstStanza || !secondStanza) throw new Error('Expected stanzas');
    expect(firstStanza.lineCount).toBe(2);
    expect(secondStanza.lineCount).toBe(1);
  });

  test('distinguishes short lines from long lines', () => {
    const tokenizer = new Tokenizer();
    const parser = new StanzaParser();

    const shortLines = tokenizer.tokenize(`Sun
Off
Glasses
Bright`);
    const shortResult = parser.detectMeter(shortLines);

    const longLines = tokenizer.tokenize(`This is a sentence about the sun`);
    const longResult = parser.detectMeter(longLines);

    expect(shortResult).not.toBe('likely-prose');
    expect(['likely-verse', 'likely-prose', 'mixed']).toContain(longResult);
  });

  test('processes identity/soul.txt', () => {
    const fs = require('fs');
    const path = require('path');

    const tokenizer = new Tokenizer();
    const parser = new StanzaParser();

    const soulPath = path.join(__dirname, '../../identity/soul.txt');
    const soulContent = fs.readFileSync(soulPath, 'utf8');
    const firstLines = soulContent.split('\n').slice(0, 30).join('\n');

    const lines = tokenizer.tokenize(firstLines);
    const structure = parser.parseStanzas(lines);

    console.log(`Processed ${structure.totalLines} lines into ${structure.totalStanzas} stanzas`);

    expect(structure.totalLines).toBeGreaterThan(0);
    expect(structure.stanzas.length).toBeGreaterThan(0);
  });
});

/**
 * Living Dialogos
 * 
 * A system for interrogating live session data, not just static chronicles.
 * Detects:
 * - Stated intents vs actual actions (gaps)
 * - Recurring concepts across sessions (semantic patterns)
 * - Emotional shifts in stated goals
 * - Temporal gaps in attention
 * - Goal-activity misalignment
 */

export interface StatedIntent {
  id: string;
  description: string;
  emotionalTone?: string;
  timestamp: number;
  sessionId: string;
}

export interface Action {
  type: string;
  file?: string;
  timestamp: number;
  sessionId: string;
}

export interface ConceptFrequency {
  concept: string;
  frequency: number;
  sessions: string[];
  firstSeen: number;
  lastSeen: number;
}

export interface EmotionalShift {
  subject: string;
  from: string;
  to: string;
  timeSpan: number;
}

export interface Gap {
  intent: string;
  status: 'pending' | 'avoided' | 'forgotten';
  timeSinceStated: number;
  priority: 'critical' | 'high' | 'medium' | 'low';
}

export interface GoalActivity {
  goalId: string;
  goalName: string;
  relevantSessions: string[];
  misaligned: boolean;
  coverage: number; // 0-1
}

export interface AttentionGap {
  start: number;
  end: number;
  duration: number;
  before: string;
  after: string;
}

export class LivingDialogos {
  private intents: Map<string, StatedIntent[]> = new Map();
  private actions: Map<string, Action[]> = new Map();
  private conceptIndex: Map<string, Map<string, number>> = new Map();
  private activityLog: { timestamp: number; activity: string }[] = [];
  private goals: Array<{
    id: string;
    name: string;
    priority: string;
    sessionIds: string[];
    status: string;
  }> = [];

  registerIntent(subject: string, intent: string | StatedIntent) {
    if (typeof intent === 'string') {
      const existing = this.intents.get(subject) || [];
      existing.push({
        id: `intent_${Date.now()}`,
        description: intent,
        timestamp: Date.now(),
        sessionId: 'current'
      });
      this.intents.set(subject, existing);
    } else {
      const existing = this.intents.get(subject) || [];
      existing.push(intent);
      this.intents.set(subject, existing);
    }
  }

  recordAction(intentSubject: string, action: Action) {
    const existing = this.actions.get(intentSubject) || [];
    existing.push(action);
    this.actions.set(intentSubject, existing);
  }

